css:
.wrapper.kbs {
  --kbs-surface: var(--block-bg-color, #15151A);
  --kbs-surface-raised: #1B1B22;
  --kbs-ink: var(--color-text, #F4F4F7);
  --kbs-muted: var(--color-gray-500, #8A8A96);
  --kbs-line: var(--color-gray-200, rgba(255,255,255,.07));
  --kbs-accent: var(--color-primary, #FFD21E);
  --kbs-accent2: var(--color-secondary, #FF3D8B);
  --kbs-success: var(--color-success, #36D399);
  --kbs-warn: #F6C453;
  --kbs-danger: var(--color-danger, #FF5A6E);
  --kbs-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  container-type: inline-size;
  color: var(--kbs-ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  padding: 2px;
}

.wrapper.kbs .kbs-head {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 8px 12px;
  margin: 0 2px 14px;
}
.wrapper.kbs .kbs-eyebrow {
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--kbs-ink);
}
.wrapper.kbs .kbs-eyebrow::before {
  content: "";
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  margin-right: 8px;
  background: var(--kbs-accent);
  vertical-align: middle;
}
.wrapper.kbs .kbs-meta {
  margin-left: auto;
  font: 600 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .02em;
  color: var(--kbs-muted);
  font-variant-numeric: tabular-nums;
}

.wrapper.kbs .kbs-kpis {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 14px;
}

.wrapper.kbs .kbs-card {
  position: relative;
  min-width: 0;
  background: var(--kbs-surface);
  border: 1px solid var(--kbs-line);
  border-radius: 14px;
  padding: 16px;
  box-shadow: var(--kbs-shadow);
  transition: background .15s ease, border-color .15s ease, box-shadow .15s ease, transform .15s ease;
}
.wrapper.kbs .kbs-card:hover {
  background: var(--kbs-surface-raised);
  border-color: color-mix(in srgb, var(--kbs-accent) 32%, var(--kbs-line));
  transform: translateY(-2px);
}

.wrapper.kbs .kbs-label {
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--kbs-muted);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.wrapper.kbs .kbs-label::before {
  content: "";
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 50%;
  margin-right: 7px;
  background: var(--kbs-accent);
  vertical-align: middle;
}
.wrapper.kbs .kbs-value {
  font: 800 26px/1.1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  font-variant-numeric: tabular-nums;
  color: var(--kbs-ink);
  margin-top: 8px;
  overflow-wrap: anywhere;
}
.wrapper.kbs .kbs-ctx {
  font: 600 11px/1.3 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--kbs-muted);
  margin-top: 5px;
}

.wrapper.kbs .kbs-card.hero {
  background: linear-gradient(135deg, var(--kbs-accent), var(--kbs-accent2));
  border-color: transparent;
  box-shadow: var(--kbs-shadow), 0 0 28px -8px color-mix(in srgb, var(--kbs-accent) 55%, transparent);
}
.wrapper.kbs .kbs-card.hero:hover {
  box-shadow: var(--kbs-shadow), 0 0 34px -6px color-mix(in srgb, var(--kbs-accent) 70%, transparent);
}
.wrapper.kbs .kbs-card.hero .kbs-label,
.wrapper.kbs .kbs-card.hero .kbs-value,
.wrapper.kbs .kbs-card.hero .kbs-ctx { color: #0B0B0D; }
.wrapper.kbs .kbs-card.hero .kbs-label { opacity: .82; }
.wrapper.kbs .kbs-card.hero .kbs-label::before { background: #0B0B0D; }

.wrapper.kbs .kbs-card.good .kbs-value { color: var(--kbs-success); }
.wrapper.kbs .kbs-card.good .kbs-label::before { background: var(--kbs-success); }
.wrapper.kbs .kbs-card.warn .kbs-value { color: var(--kbs-warn); }
.wrapper.kbs .kbs-card.warn .kbs-label::before { background: var(--kbs-warn); }
.wrapper.kbs .kbs-card.bad .kbs-value { color: var(--kbs-danger); }
.wrapper.kbs .kbs-card.bad .kbs-label::before { background: var(--kbs-danger); }
.wrapper.kbs .kbs-card.bad {
  border-color: color-mix(in srgb, var(--kbs-danger) 38%, var(--kbs-line));
  box-shadow: var(--kbs-shadow), 0 0 22px -10px color-mix(in srgb, var(--kbs-danger) 55%, transparent);
}
.wrapper.kbs .kbs-card.bad:hover {
  border-color: color-mix(in srgb, var(--kbs-danger) 55%, var(--kbs-line));
  box-shadow: var(--kbs-shadow), 0 0 26px -8px color-mix(in srgb, var(--kbs-danger) 65%, transparent);
}

.wrapper.kbs .kbs-empty {
  grid-column: 1 / -1;
  padding: 24px;
  text-align: center;
  background: var(--kbs-surface);
  border: 1px solid var(--kbs-line);
  border-radius: 14px;
  color: var(--kbs-muted);
  font: 600 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

@media (prefers-reduced-motion: reduce) {
  .wrapper.kbs .kbs-card { transition: none; }
  .wrapper.kbs .kbs-card:hover,
  .wrapper.kbs .kbs-card.hero:hover { transform: none; }
}

@container (max-width: 1100px) {
  .wrapper.kbs .kbs-kpis { grid-template-columns: repeat(3, minmax(0, 1fr)); }
}
@container (max-width: 640px) {
  .wrapper.kbs .kbs-kpis { grid-template-columns: repeat(2, minmax(0, 1fr)); }
}
@container (max-width: 380px) {
  .wrapper.kbs .kbs-kpis { grid-template-columns: 1fr; }
}
